import { NextResponse } from "next/server";
import bcrypt from "bcryptjs";

export async function GET() {
  if (process.env.NODE_ENV !== "development") {
    return NextResponse.json({ error: "Not available" }, { status: 404 });
  }
  const hash = process.env.ADMIN_PASSWORD_HASH;
  const plain = process.env.ADMIN_PASSWORD;
  const testPw = "pragma_admin_2024";
  let hashMatch = false;
  if (hash) hashMatch = await bcrypt.compare(testPw, hash);
  return NextResponse.json({
    ADMIN_PASSWORD_HASH_set: !!hash,
    ADMIN_PASSWORD_set: !!plain,
    hashMatchesPragmaAdmin: hashMatch,
    plainMatchesPragmaAdmin: plain === testPw,
  });
}

